import calendar
from datetime import date

def generar_calendario(anio=None, mes=None):
    if anio is None:
        anio = date.today().year
    if mes is None:
        mes = date.today().month
    cal = calendar.TextCalendar(firstweekday=6)
    return cal.formatmonth(anio, mes)

if __name__ == "__main__":
